class Solution {
public:
    vector<int> powerfulIntegers(int x, int y, int bound) {
        unordered_set<int> res;
        for (long i = 1; i <= bound; i *= x) {
            for (long j = 1; i + j <= bound; j *= y) {
                res.insert(i + j);
                if (y == 1) break;
            }
            if (x == 1) break;
        }
        vector<int> ans(res.begin(), res.end());
        return ans;
    }
};
